export class MockDataService {
  static initializeData(): void {
    const existingOrders = localStorage.getItem(STORAGE_KEYS.ORDERS);
    if (!existingOrders) {
      localStorage.setItem(STORAGE_KEYS.ORDERS, JSON.stringify(INITIAL_ORDERS));
    }
  }

  static getOrders(role: UserRole, userId?: string): Order[] {
    const ordersJson = localStorage.getItem(STORAGE_KEYS.ORDERS);
    if (!ordersJson) return [];
    
    const orders: Order[] = JSON.parse(ordersJson);
    
    if (role === 'admin') {
      return orders.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
    } else {
      return orders
        .filter(order => order.dentistId === userId)
        .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
    }
  }

  static createOrder(orderData: Omit<Order, 'id' | 'createdAt' | 'dentistName'>, user: User): Order {
    const ordersJson = localStorage.getItem(STORAGE_KEYS.ORDERS);
    const orders: Order[] = ordersJson ? JSON.parse(ordersJson) : [];
    
    const newOrder: Order = {
      ...orderData,
      id: `ORD-${String(orders.length + 1).padStart(3, '0')}`,
      createdAt: new Date().toISOString(),
      dentistId: user.id,
      dentistName: user.name,
    };
    
    orders.unshift(newOrder);
    localStorage.setItem(STORAGE_KEYS.ORDERS, JSON.stringify(orders));
    
    return newOrder;
  }

  static updateOrderStatus(orderId: string, status: OrderStatus): void {
    const ordersJson = localStorage.getItem(STORAGE_KEYS.ORDERS);
    if (!ordersJson) return;
    
    const orders: Order[] = JSON.parse(ordersJson);
    const orderIndex = orders.findIndex(o => o.id === orderId);
    
    if (orderIndex !== -1) {
      orders[orderIndex].status = status;
      localStorage.setItem(STORAGE_KEYS.ORDERS, JSON.stringify(orders));
    }
  }

  static getOrderById(orderId: string): Order | null {
    const ordersJson = localStorage.getItem(STORAGE_KEYS.ORDERS);
    if (!ordersJson) return null;
    
    const orders: Order[] = JSON.parse(ordersJson);
    return orders.find(o => o.id === orderId) || null;
  }
  
  static authenticate(username: string): User | null {
    // Simple mock authentication
    return MOCK_USERS.find(u => u.username === username) || null;
  }
}
